async (page) => {
  // Set attack style to Hack (index 0) for Strength XP
  await page.evaluate(() => window.game.player.setAttackStyle(0));
  await page.waitForTimeout(500);
  // Click the item drop visible on screen at ~(810, 383)
  await page.evaluate(({x, y}) => {
    const canvas = document.getElementById('canvas');
    canvas.dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, { x: 810, y: 383 });
  await page.waitForTimeout(2000);
  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  return 'Set Hack style, clicked item drop';
}

