async (page) => {
  await page.evaluate(() => {
    const btn = document.getElementById('quest-button');
    if (btn) btn.click();
  });
  await page.waitForTimeout(1500);
  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    const foresting = s?.quests?.find(q => q.key === 'foresting');
    return {pos: s?.player_position, foresting, inventory: s?.inventory};
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  return JSON.stringify(state);
}

async (page) => {
  // Check player equipment
  const equip = await page.evaluate(() => {
    try {
      const player = window.game?.player;
      if (!player) return 'no player';
      // Try to get equipment
      const equipment = player.equipment || player.getEquipment?.() || {};
      const weapon = player.weapon || equipment.weapon || player.getWeapon?.();
      return {
        equipment: JSON.stringify(equipment),
        weapon: weapon ? JSON.stringify(weapon) : 'none'
      };
    } catch(e) {
      return {error: e.message};
    }
  });
  return JSON.stringify(equip);
}

